SELECT c.id, c.post_id, c.user_id, c.parent_id, c.reply_to_user_id, c.reply_to_user_name, c.content, c.status, c.create_time, u.username as user_name, u.nickname as user_nickname, u.avatar as user_avatar, p.title as post_title FROM post_comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN post p ON c.post_id = p.id
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%'))
AND c.status = #{status}
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM post_comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN post p ON c.post_id = p.id
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR p.title LIKE CONCAT('%', #{keyword}, '%'))
AND c.status = #{status}

WITH RECURSIVE comment_tree AS (
    SELECT id, parent_id FROM post_comment WHERE id = #{parentId}
    UNION ALL
    SELECT c.id, c.parent_id
    FROM post_comment c
             INNER JOIN comment_tree ct ON c.parent_id = ct.id
)
SELECT id FROM comment_tree WHERE id != #{parentId}
